  CLASS
	NAME "Evapotranspiración real (mm)"
    EXPRESSION ([pixel] = -99999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "26 - 30"
    EXPRESSION ([pixel] >= 26 AND [pixel] < 30)
    COLOR 54 145 33
  END
  CLASS
	NAME "30 - 35"
    EXPRESSION ([pixel] >= 30 AND [pixel] < 35)
    COLOR 149 199 105
  END
  CLASS
	NAME "35 - 40"
    EXPRESSION ([pixel] >= 35 AND [pixel] < 40)
    COLOR 102 217 129
  END
  CLASS
	NAME "40 - 45"
    EXPRESSION ([pixel] >= 40 AND [pixel] < 45)
    COLOR 204 230 76
  END
  CLASS
	NAME "45 - 50"
    EXPRESSION ([pixel] >= 45 AND [pixel] < 50)
    COLOR 235 255 153
  END
  CLASS
	NAME "50 - 70"
    EXPRESSION ([pixel] >= 50 AND [pixel] < 70)
    COLOR 250 250 95
  END
  CLASS
	NAME "70 - 90"
    EXPRESSION ([pixel] >= 70 AND [pixel] < 90)
    COLOR 255 208 0
  END
  CLASS
	NAME "90 - 100"
    EXPRESSION ([pixel] >= 90 AND [pixel] < 100)
    COLOR 255 134 128
  END
  CLASS
	NAME "100 - 110"
    EXPRESSION ([pixel] >= 100 AND [pixel] <= 120)
